import React, { useState, useEffect, useRef } from 'react';

const images = [
  '/images/login%201.jpg',
  '/images/login%202.jpg',
  '/images/chat%20screen%201.jpg',
  '/images/outcoming%201.jpg',
  '/images/outcoming%202.jpg',
];

function TechGlobeSection() {
  const [currentImage, setCurrentImage] = useState(0);
  const [imageVisible, setImageVisible] = useState(true);
  const [currentVideo, setCurrentVideo] = useState(0);
  const [videoFade, setVideoFade] = useState(true);
  const videoRef = useRef(null);
  const timerRef = useRef(null);

  // Image slideshow - 2s each with reveal animation
  useEffect(() => {
    const cycle = () => {
      // Show for 2s
      setImageVisible(true);
      timerRef.current = setTimeout(() => {
        // Fade out
        setImageVisible(false);
        timerRef.current = setTimeout(() => {
          // Next image
          setCurrentImage((prev) => (prev + 1) % images.length);
        }, 500);
      }, 2000);
    };
    cycle();
    const interval = setInterval(cycle, 2800);
    return () => {
      clearInterval(interval);
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, []);

  // Video carousel - video 1 full, video 2 only 4s
  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const handleTimeUpdate = () => {
      if (currentVideo === 1 && video.currentTime >= 4) {
        video.pause();
        setVideoFade(false);
        setTimeout(() => {
          setCurrentVideo(0);
          video.src = '/videos/video%20laptop.mp4';
          video.currentTime = 0;
          video.play();
          setVideoFade(true);
        }, 500);
      }
    };

    const handleEnded = () => {
      if (currentVideo === 0) {
        setVideoFade(false);
        setTimeout(() => {
          setCurrentVideo(1);
          video.src = '/videos/send%20images.mp4';
          video.currentTime = 0;
          video.play();
          setVideoFade(true);
        }, 500);
      }
    };

    video.addEventListener('timeupdate', handleTimeUpdate);
    video.addEventListener('ended', handleEnded);
    return () => {
      video.removeEventListener('timeupdate', handleTimeUpdate);
      video.removeEventListener('ended', handleEnded);
    };
  }, [currentVideo]);

  return (
    <section className="relative py-20 px-4 sm:px-6 lg:px-8 overflow-hidden bg-white">
      <style>{`
        @keyframes revealFromCenter {
          0% {
            clip-path: inset(50% 50% 50% 50% round 12px);
            opacity: 0;
          }
          100% {
            clip-path: inset(0% 0% 0% 0% round 12px);
            opacity: 1;
          }
        }
        @keyframes closeToCenter {
          0% {
            clip-path: inset(0% 0% 0% 0% round 12px);
            opacity: 1;
          }
          100% {
            clip-path: inset(50% 50% 50% 50% round 12px);
            opacity: 0;
          }
        }
        .reveal-in {
          animation: revealFromCenter 0.5s ease-out forwards;
        }
        .reveal-out {
          animation: closeToCenter 0.4s ease-in forwards;
        }
      `}</style>

      <div className="relative max-w-6xl mx-auto">
        <div className="text-center mb-12">
          <h2 className="text-4xl font-bold text-gray-900 mb-4">Sản Phẩm Của Chúng Tôi</h2>
          <p className="text-gray-500 text-lg">Xem demo trực tiếp sản phẩm đã triển khai</p>
        </div>

        <div className="flex flex-col lg:flex-row gap-8 items-center">
          {/* Left - Video */}
          <div className="w-full lg:w-1/2">
            <div 
              className="relative rounded-2xl overflow-hidden shadow-2xl transition-opacity duration-500"
              style={{ aspectRatio: '16/9', background: '#000', opacity: videoFade ? 1 : 0 }}
            >
              <video
                ref={videoRef}
                className="absolute inset-0 w-full h-full object-cover"
                autoPlay
                muted
                playsInline
                src="/videos/video%20laptop.mp4"
              />
            </div>
          </div>

          {/* Right - Image slideshow with reveal animation */}
          <div className="w-full lg:w-1/2 flex items-center justify-center">
            <div className="relative w-full" style={{ aspectRatio: '9/16', maxHeight: '500px', maxWidth: '280px' }}>
              {images.map((src, index) => (
                <img
                  key={`${index}-${currentImage}`}
                  src={src}
                  alt={`Screenshot ${index + 1}`}
                  className={`absolute inset-0 w-full h-full object-cover rounded-xl shadow-lg ${
                    index === currentImage ? (imageVisible ? 'reveal-in' : 'reveal-out') : ''
                  }`}
                  style={{
                    display: index === currentImage ? 'block' : 'none',
                  }}
                />
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default TechGlobeSection;
